              <style>{`
                svg {
                  --bg: transparent;
                  --toast: #efeedd;
                  --check: #efeedd;
                  --toast-width: 18;
                  --check-width: 32;
                }
                .bg { fill: var(--bg); }
                .toast { fill: none; stroke: var(--toast); stroke-width: var(--toast-width); stroke-linecap: round; stroke-linejoin: round; }
                .check { fill: none; stroke: var(--check); stroke-width: var(--check-width); stroke-linecap: round; stroke-linejoin: round; }
              `}</style>
